var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그들이야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼らだからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that these employees whom you'd been giving a lot of thought were absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他們是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그들과 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼らとともにいることを。","ENG":"that you'll be with them, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他們一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called them to your office. They said they'd be here soon.","TWN":"做好心理準備後，你將他們傳喚到老闆辦公室，他們說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_NULL","text":{"KOREA":"기억합니다. 초목의 냄새, 햇살과 바람을 느끼는 것만으로 만족하던 시절을.","JPN":" 忘れていません。草木の匂いや日の光と風を感じるだけでも幸せだった頃のことは。","ENG":" We remember. The days when I was just happy to smell the grass and feel the sun and cool breeze on my skin.","TWN":"我記得，以前光是聞到草的味道，感受到陽光和微風，就令人心滿意足。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_NULL","text":{"KOREA":"하지만 곁의 이들이 병과 사고로 죽어갈 때, 우리는 처음으로 의문을 품었습니다.","JPN":" ですが、近しい者たちが病気や事故で死んでいくとき、私たちは初めて疑問を持ちました。","ENG":" But when people close to us started dying from disease or accidents, we started having doubts.","TWN":"但身邊的人因為疾病和意外而死去時，我們第一次產生懷疑。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_NULL","text":{"KOREA":"인간은 어디에서 오고, 어디로 가는가? 거기엔 어떠한 신의 뜻이 있는가?","JPN":" 人間はどこから来て、どこへ行くのか。そこにはどのような神のご意志があるのか。","ENG":" Where does man come from and go? And greater will is there to that?","TWN":"人類是從何處來，又要往何處去？這其中有神的旨意嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_NULL","text":{"KOREA":"그리고 깨닫습니다. 풀이 자라는 것도, 바람이 부는 것도, 그 이유를 찾고자 하면 기적이나 은총이 아닌 아주 간단한 지식 속에 해답이 있음을.","JPN":" そして悟りました。草が育つことも風が吹くことも、その理由を奇跡や恩寵に探さずとも、至極簡単な知識の中に答えがあるということを。","ENG":" Then we realized. If you try to find out why grass grows or the wind blows, there is an answer in very simple knowledge, not miracles or grace.","TWN":"於是發現，樹之所以能生長，風之所以能吹拂，並不是因為神的祝福，答案就在非常簡單的知識裡。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_NULL","text":{"KOREA":"그렇다면 죽음 또한… 결국 우리가 탐구할 수 있는 지식의 영역에 있다는 것을.","JPN":" であれば、死もまた……私たちが探求できる知識の領域にあるのだということを。","ENG":" But that would imply that death is also placed... where we might find answers.","TWN":"若是如此，那麼死亡…也在可以探索的知識領域裡。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_NULL","text":{"KOREA":"그렇게 우리는 죽음에 얽매이지 않을 지식을 갈구합니다.","JPN":" そうして、私たちは死に縛られない知識を切に求めるようになりました。","ENG":" So we long for knowledge that could make us free from death.","TWN":"因此我們追求不受死亡限制的知識。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_NULL","text":{"KOREA":"그것을 우리는 영원한 치유라고 부릅니다.","JPN":" 私たちの間でそれは永遠の治癒と呼ばれています。","ENG":" That is what we refer to as the \\"Eternal cure\\".","TWN":"那稱之為永遠的治癒。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_NULL","text":{"KOREA":"우리의 연구에 동참하세요, 오래된 목소리여. 당신은 우리가 찾는 지식의 거대한 지표가 될 것입니다.","JPN":" 古い声よ、共に研究しましょう。あなたは私たちが探す知識の大きな指標となるでしょう。","ENG":" Join us in our research, Old Voice. You will be a shining guide of the knowledge we seek.","TWN":"老聲音，加入我們的研究吧。你會成為我們尋找知識的里程碑。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};